form:Form.form:Scripts:
		var CFG;
var TIT=null;   
var zoom;
var cut; 
var copy;
var clsReport;



function ReplaceResource(recID)
{
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS      
function EnableButtons()
{
	switch(Ctrl("VARIABLE_LIST_ID").GetXValue().split("/").length)
	{
		case 1: //Workflow
			CtrlEnabled("SHOW"  ,false);
			CtrlEnabled("ADD"   ,true);
			CtrlEnabled("EDIT"  ,false);
			CtrlEnabled("DELETE",false);
			CtrlEnabled("VALUES",false);
			CtrlEnabled("UP"    ,false);
			CtrlEnabled("DW"    ,false);
			break;

		case 2: //Grupos de Variables
			CtrlEnabled("SHOW"  ,true);
			CtrlEnabled("ADD"   ,true);
			CtrlEnabled("EDIT"  ,true);
			CtrlEnabled("DELETE",true);
			CtrlEnabled("VALUES",false);
			CtrlEnabled("UP"    ,false);
			CtrlEnabled("DW"    ,false);
  		break;

		case 3: //Variables          
			objItem=clsReport.GetItem(Ctrl("VARIABLE_LIST_ID").GetXValue());
			CtrlEnabled("SHOW"  ,true);
			CtrlEnabled("ADD"   ,false);
			CtrlEnabled("EDIT"  ,true);
			CtrlEnabled("DELETE",true);
			CtrlEnabled("VALUES",objItem.Tag=="enum"?true:false);
			CtrlEnabled("UP"    ,true);
			CtrlEnabled("DW"    ,true);
			break;
	}                                                  
}

function LoadChildsReport(objTree, objGroup)
{    
	var RS;
	var param=new NomadXML("PARAM");
	param.SetAttr("oi_wf", Ctrl("PARENT").GetXValue());

	switch(objGroup.FullId.split("/").length)
	{
		case 1: //Grupos de Variables                                                     
			RS=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_VAR_GROUP_LIST"),param.ToString());
			break;

		case 2: //Variables
			param.SetAttr("oi_var_group", objGroup.FullId.split("/")[1]);
			RS=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_VAR_LIST"),param.ToString());
			break;
	}                                                  

	objTree.SetXML(objGroup.FullId, RS.ToString());
}

function ReloadTree()
{                                          
	Ctrl("VARIABLE_LIST_ID").SetXValue("");

	///////////////////////////////////////////////////////////////////////////////////////////		                   
	//XML de METADATOS
	var ELE=new NomadXML("tree");

	var RT=ELE.AddTailElement("group");
	RT.SetAttr("id"      ,"WF");
	RT.SetAttr("label"   ,"Workflow "+Ctrl("PAR").GetXValue());
	RT.SetAttr("imgOpen" ,"cabinet.ico");
	RT.SetAttr("imgClose","cabinet-close.ico");

	clsReport=clsClientTree("VARIABLE_LIST","VARIABLE_LIST_ID","CLOCK.ico","folder-close.ico","folder.ico","REP.ICO",true,LoadChildsReport,null,EnableButtons);
	clsReport.SetXML(null, ELE.ToString());
	clsReport.ClickExpGroup("WF");

	//Habilitar Botones
	EnableButtons();
}

function OnLoad()
{        
	//Cargo la Configuracion
	CFG   =new NomadXML(Ctrl("main").getResource("QRY_CFG"));

	//Modifico los Recursos
	ReplaceResource("QRY_IDS_PARENT");                 

	//Actualizo el Titulo
	if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
	{
		if (TIT==null)
			TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

		if (TIT!=null) TIT=TIT.FirstChild();
		if (TIT!=null && TIT.GetAttr("descr")!="")
			Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	}     

	//Actualizo la Pantalla
	ReloadTree();
}


////////////////////////////////////////////////////////////////////////////////////////////////
function RegAdd()     
{
	var id,objGroup,objItem,wf; 
	if (Ctrl("ADD")?false:true) return false;
	if (!Ctrl("ADD").GetEnabled()) return false;    

	id=Ctrl("VARIABLE_LIST_ID").GetXValue().split("/");
	switch(id.length)
	{
		case 1:
			wf=Ctrl("PARENT").GetXValue();
			objGroup=null;
			objItem=null;
			break;
		case 2:
			wf=Ctrl("PARENT").GetXValue();
			objGroup=clsReport.GetGroup(id.join("/")); id.length--;
			objItem=null;
			break;
		case 3:                  
			wf=Ctrl("PARENT").GetXValue();
			objItem=clsReport.GetItem(id.join("/")); id.length--;
			objGroup=clsReport.GetGroup(id.join("/")); id.length--;
			break;
	}

	switch(Ctrl("VARIABLE_LIST_ID").GetXValue().split("/").length)
	{
		case 1: //Workflow
			openNewFlowWait("NucleusWF.Base.Definicion.Workflows.VAR_GROUP.MAIN.STD.autoflow","ADD",'<PARAM PARENT="'+wf+'" />',new FlowResult(Ctrl("VARIABLE_LIST_ID").GetXValue()),"L");
			break;

		case 2: //Grupos de Variables                                           
			openNewFlowWait("NucleusWF.Base.Definicion.Workflows.VAR.flow","ADD",'<PARAM PARENT="'+objGroup.Id+'" />',new FlowResult(Ctrl("VARIABLE_LIST_ID").GetXValue()),"L");
  		break;

		case 3: //Grupos de Variables
			break;
	}                                                  
	return true; 
}

function RegShow()    
{
	var id,objGroup,objItem,wf; 
	if (Ctrl("EDIT")?false:true) return false;
	if (!Ctrl("EDIT").GetEnabled()) return false;    

	id=Ctrl("VARIABLE_LIST_ID").GetXValue().split("/");
	switch(id.length)
	{
		case 1:
			wf=Ctrl("PARENT").GetXValue();
			objGroup=null;
			objItem=null;
			break;
		case 2:
			wf=Ctrl("PARENT").GetXValue();
			objGroup=clsReport.GetGroup(id.join("/")); id.length--;
			objItem=null;
			break;
		case 3:                  
			wf=Ctrl("PARENT").GetXValue();
			objItem=clsReport.GetItem(id.join("/")); id.length--;
			objGroup=clsReport.GetGroup(id.join("/")); id.length--;
