		case 2: //Grupos de Variables                                           
			openNewFlowWait("NucleusWF.Base.Definicion.Workflows.VAR_GROUP.MAIN.STD.autoflow","SHOW",'<PARAM PARENT="'+wf+'" ID="'+objGroup.Id+'" />',new FlowResult(Ctrl("VARIABLE_LIST_ID").GetXValue()),"L");
  		break;

		case 3: //Grupos de Variables
			openNewFlowWait("NucleusWF.Base.Definicion.Workflows.VAR.flow","SHOW",'<PARAM PARENT="'+objGroup.Id+'" ID="'+objItem.Id+'" />',new FlowResult(Ctrl("VARIABLE_LIST_ID").GetXValue()),"L");
			break;
	}                                                  
	return true; 
}

