function EditValues()
{    
	var id=Ctrl("VARIABLE_LIST_ID").GetXValue().split("/"); id=id[id.length-1];
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.VAR_COMBO.MAIN.STD.autoflow","LIST",'<PARAM PARENT="'+id+'" />',new FlowResult(Ctrl("VARIABLE_LIST_ID").GetXValue()),"L");
}


function FlowResult(selectID)
{
	this.lastID=selectID;
	this.processResult = function(xml)
	{          
		var id=Ctrl("VARIABLE_LIST_ID").GetXValue().split("/");

		switch(id.length)
		{
			case 1: //Workflow
			case 2: //Grupos de Variables         
				ReloadTree();
				break;

			case 3: //Variables
				id.length--;
				objGroup=clsReport.GetGroup(id.join("/"));                                  
				LoadChildsReport(clsReport, objGroup);
				break;
		}                                                  
	}
}
